func TestExecutorRegistry_ListTools(t *testing.T) {
	registry := agentictools.NewExecutorRegistry()

	// Register multiple tools
	tools := []struct {
		name string
		desc string
	}{
		{"graph_query", "Query the knowledge graph"},
		{"file_read", "Read a file"},
		{"file_write", "Write a file"},
	}

	for _, tool := range tools {
		executor := &mockToolExecutor{
			name: tool.name,
			listToolsFunc: func() []agentic.ToolDefinition {
				return []agentic.ToolDefinition{
					{
						Name:        tool.name,
						Description: tool.desc,
						Parameters: map[string]any{
							"type": "object",
						},
					},
				}
			},
		}
		if err := registry.RegisterTool(tool.name, executor); err != nil {
			t.Fatalf("RegisterTool(%s) failed: %v", tool.name, err)
		}
	}

	// List all tools
	allTools := registry.ListTools()

	if len(allTools) != len(tools) {
		t.Errorf("ListTools() count = %d, want %d", len(allTools), len(tools))
	}

	// Verify all tools are present
	toolMap := make(map[string]agentic.ToolDefinition)
	for _, tool := range allTools {
		toolMap[tool.Name] = tool
	}

	for _, expected := range tools {
		tool, ok := toolMap[expected.name]
		if !ok {
			t.Errorf("ListTools() missing tool %q", expected.name)
			continue
		}
		if tool.Description != expected.desc {
			t.Errorf("Tool %q description = %q, want %q", expected.name, tool.Description, expected.desc)
		}
	}
}

